                for dx, dy in [(2, 2), (2, -2), (-2, 2), (-2, -2)]:
                    nx, ny = i + dx // 2, j + dy // 2
                    if 0 <= nx < 8 and 0 <= ny < 8 and board[nx][ny] == ' ':
                        return True

    return False

def check_winner(board):
    white_count = sum(row.count('R') for row in board) + sum(row.count('Q') for row in board)
    black_count = sum(row.count('r') for row in board) + sum(row.count('q') for row in board)

    if white_count == 0:
        return 'Black wins'
    if black_count == 0:
        return 'White wins'

    if not has_legal_moves(board):
        if white_count > black_count:
            return 'White wins'
        elif white_count < black_count:
            return 'Black wins'
        else:
            return 'Draw'
